view.template:
{% load view_tags %}

{% get_set 'project/obligation/obligation_purpose_legal_basis/obligation_purpose_legal_basis_id' as duties_purposes %}
{% get_set 'project/obligation/obligation_data_categories/obligation_data_categories_id' as data_categories %}
{% get_set 'project/obligation/obligation_special_category/obligation_special_category_id' as data_categories_s %}
{% get_set 'project/obligation/obligation_third_country/obligation_third_country_id' as third_countries %}
{% get_set 'project/obligation/receiver/receiver_id' as receivers %}


{# ------------------ANSCHREIBEN---------------------------- #} 

<h1>
  {% get_value 'project/information/information_project_name' as info_project_name %}
  Studieninformationen für Teilnehmende 
  {% if info_project_name.is_true %}
    zum Projekt {{ info_project_name.value }}
  {% endif %}
</h1>

<p>
  {% render_value 'project/information/information_salutation' %}
</p>

{% get_value 'project/information/information_project_description' as info_project_description %}
{% if info_project_description.is_true %}
  <p>
  {{ info_project_description.value }}
  </p>
{% endif %}

<p>
  {% render_value 'project/information/information_approval' %}
</p>

<p>
  {% render_value 'project/information/information_project_expectation' %}
</p>

<p>
  {% render_value 'project/information/information_compensation' %}
</p>

<p>
  {% render_value 'project/information/information_risks' %}
</p>

<p>
  {% get_value 'project/information/information_ethics' as ethics %}
  {{ ethics.text }}
</p>

<p>
  Bei Rückfragen oder Verständnisschwierigkeiten können Sie sich gerne an  
  {% get_value 'project/information/information_questions_person' as info_resp_person %}
  {% if info_resp_person.is_true %}
    {{ info_resp_person.value }}
  {% else %}
    die verantwortlichen Personen dieses Projekts 
  {% endif %}
  wenden. 
</p>

<p>
{% render_value 'project/information/information_declaration_consent_voluntary' %}
</p>

<p>
  Wenn Sie alles in Ruhe gelesen haben und mit unserem Vorhaben einverstanden sind, unterschreiben Sie bitte die nachfolgende Einwilligungserklärung "Einwilligung in die Teilnahme und Datenverarbeitung" und geben uns diese <b>vor</b> der Studienteilnahme zurück.
</p>

<p>
  {% render_value 'project/information/information_thanks' %}
</p>

<p>
  Mit freundlichen Grüßen 
</p>

{% get_value 'project/information/information_sender' as info_sender %}
{% if info_sender.is_true %}
  <p>
    {{ info_sender.value }} 
  </p>
{% else %}
  <p>
    Die Projektleitung
  </p>
{% endif %}

<br>

{# ------------------INFORMATIONEN IN ANSCHREIBEN-------- #} 

{% get_value 'project/information/information_project_homepage' as info_project_homepage %}
{% if info_project_homepage.is_true %}
  <b>Homepage zur Studie:</b>
  <p>
  {{ info_project_homepage.value }}
  </p>
{% endif %}

{% get_value 'project/information/information_project_lead' as info_project_lead %}
{% if info_project_lead.is_true %}
  <b>Studienleitung:</b>
  <p>
  {{ info_project_lead.value }}
  </p>
{% endif %}

{% get_value 'project/information/information_participants' as info_project_participants %}
{% if info_project_participants.is_true %}
  <b>Studienbeteiligte:</b>
  <p>
  {{ info_project_participants.value }}
  </p>
{% endif %}

{% get_value 'project/information/information_funding' as info_funding %}
{% if info_funding.is_true %}
  <b>Auftrag- oder Fördergeber:</b>
  <p>
  Die Studie wird gefördert von 
  {{ info_funding.value }}
  </p>
{% endif %}

{% get_value 'project/information/information_id' as info_id %}
{% if info_id.is_true %}
  <p>
  <b>Projekt-ID: </b>
  {{ info_id.value }}
  </p>
{% endif %}

<br>
<br>


{# ---------------------------------------------- #} 
{# ----INFORMATIONSPFLICHTEN ZUM DATENSCHUTZ----- #} 
{# ---------------------------------------------- #} 

<h2>Informationspflichten zum Datenschutz</h2>

<p>
Wir verarbeiten Ihre Daten gemäß den Vorschriften der Datenschutzgrundverordnung (DSGVO) sowie allen weiteren einschlägigen datenschutzrechtlichen Bestimmungen. Mit den vorliegenden Datenschutzhinweisen kommen wir zugleich unserer Informationspflicht nach Artikel 13 der EU‑Datenschutzgrundverordnung (DSGVO) nach. 
</p>

<b>Kontaktdaten der verantwortlichen Stelle(n)</b>
<p>
  {% get_value 'project/obligation/obligation_data_handling_responsible' as responsible_body %}

  {% if responsible_body.is_true %}
    {{ responsible_body.value }}
  {% else %}
    <b><span style="color:Red;">!!!</span></b> Sie müssen Namen und Kontaktmöglichkeiten der für den Datenschutz verantwortlichen Stelle in diesem Projekt angeben (siehe Seite "Verantwortliche") <b><span style="color:Red;">!!!</span></b>
  {% endif %}
</p>


{% get_value 'project/obligation/obligation_data_protection_officer_yes_no' as data_protection_officer_y_n %}
{% if data_protection_officer_y_n.option_uri == "https://fdm.tu-dortmund.de/options/option_consent_gen_yes" %}
  <br>
  <b>Kontaktdaten der Datenschutzbeauftragten</b>
  <p>
    {% get_value 'project/obligation/obligation_data_protection_officer' as data_protection_officer %}

    {% if data_protection_officer.is_true %}
      {{ data_protection_officer.value }}
    {% else %}
      <b><span style="color:Red;">!!!</span></b> Sie haben angegeben, dass es eine(n) Datenschutzbeauftragte(n) an Ihrer Institution gibt, aber keinen Namen und Kontaktmöglichkeiten eingegeben (siehe Seite "Verantwortliche") <b><span style="color:Red;">!!!</span></b>
    {% endif %}
  </p>
{% else %}
  <br>
  <b>Kontakt bei Fragen zum Datenschutz</b>
  <p>
    {% get_value 'project/obligation/obligation_data_protection_officer_alternative' as data_protection_officer_alt %}

    {% if data_protection_officer_alt.is_true %}
      {{ data_protection_officer_alt.value }}
    {% else %}
      <b><span style="color:Red;">!!!</span></b> Sie haben keinen Namen und Kontaktmöglichkeiten für Fragen zum Datenschutz eingegeben (siehe Seite "Verantwortliche") <b><span style="color:Red;">!!!</span></b>
    {% endif %}
  </p>
{% endif %}



<br>
<b>Zwecke und Rechtsgrundlagen der Verarbeitung</b>
<p>
  Wir verarbeiten Ihre Daten für die nachfolgend genannten Zwecke 
  auf Basis der genannten Rechtsgrundlagen:

  {% if duties_purposes|length == 0 %}
    <br>
    <b><span style="color:Red;">!!!</span></b> Sie haben keinen Zweck angegeben (siehe Seite "Zwecke und Rechtsgrundlagen") 
	<b><span style="color:Red;">!!!</span></b>
  {% endif %}

    <table border="1">
      <tr><th>Zweck der Datenverarbeitung </th> <th>Rechtsgrundlage  </th></tr> 
      {# Seite Zwecke und Rechtsgrundlagen #} 
      {% for obligation_purpose in duties_purposes %}
      <tr>
        <td> 
		  {% get_set_value obligation_purpose 'project/obligation/obligation_purpose_legal_basis/obligation_purpose' as ob_purpose %}
		  {% if ob_purpose.is_true %}
		    {{ ob_purpose.value }}
		  {% else %}
		    <b><span style="color:Red;">!!!</span></b> Sie haben keinen Zweck angegeben (siehe Seite "Zwecke und Rechtsgrundlagen") 
			<b><span style="color:Red;">!!!</span></b>
		  {% endif %}
        </td> 
        <td>
		  {% get_set_values obligation_purpose 'project/obligation/obligation_purpose_legal_basis/obligation_legal_basis' as ob_purposes %}
		  {% if ob_purposes|length == 0 %}
            <b><span style="color:Red;">!!!</span></b> Sie haben keine Rechtsgrundlage angegeben (siehe Seite "Zwecke und Rechtsgrundlagen") 
			<b><span style="color:Red;">!!!</span></b>
		  {% endif %}
		  {% if ob_purposes|length > 1 %}
		    <ul>
		    {% for obp in ob_purposes %}
              <li>{{ obp.value }}</li>
		    {% endfor %}
		    </ul>
		  {% else %}
		    {% for obp in ob_purposes %}
              {{ obp.value }}
		    {% endfor %}
		  {% endif %}
        </td>
      </tr>
      {% endfor %} 

      {# Seite Nachnutzung -> Veröffentlichung, Nachnutzung, Lehre #} 

	  {% get_value 'project/obligation/obligation_publication_y_n' as publication_y_n %}
	  {% get_value 'project/obligation/obligation_publication_purpose' as publication_purpose %}
	  {% get_values 'project/obligation/obligation_publication_legal_basis' as publication_legal_basis %}

	  {% get_value 'project/obligation/obligation_lectures_y_n' as lectures_y_n %}
	  {% get_value 'project/obligation/obligation_lectures_purpose' as lectures_purpose %}
	  {% get_values 'project/obligation/obligation_lectures_legal_basis' as lectures_legal_basis %}

      {% if publication_y_n.option_uri == "https://fdm.tu-dortmund.de/options/option_consent_gen_yes" %}
      <tr>
        <td> 
		  {% if publication_purpose.is_true %}
            {{ publication_purpose.value }}
		  {% else %}
		    <b><span style="color:Red;">!!!</span></b> Sie haben keinen Zweck angegeben (siehe Seite "Wissenschaftliche Veröffentlichung") 
		    <b><span style="color:Red;">!!!</span></b>
		  {% endif %}
		</td>
        <td>
		{% if publication_legal_basis|length == 0 %}
            <b><span style="color:Red;">!!!</span></b> Sie haben keine Rechtsgrundlage angegeben (siehe Seite "Wissenschaftliche Veröffentlichung") 
			<b><span style="color:Red;">!!!</span></b>
		{% endif %}
		{% if publication_legal_basis|length > 1 %}
		    <ul>
		    {% for plb in publication_legal_basis %}
              <li>{{ plb.value }}</li>
		    {% endfor %}
		    </ul>
		  {% else %}
		    {% for plb in publication_legal_basis %}
              {{ plb.value }}
		    {% endfor %}
		  {% endif %}
        </td>
      </tr>
	  {% endif %}

	  {% if lectures_y_n.option_uri == "https://fdm.tu-dortmund.de/options/option_consent_gen_yes" %}
	  <tr>
	    <td>
		  {% if lectures_purpose.is_true %}
            {{ lectures_purpose.value }}
		  {% else %}
		    <b><span style="color:Red;">!!!</span></b> Sie haben keinen Zweck angegeben (siehe Seite "Lehre") 
		    <b><span style="color:Red;">!!!</span></b>
		  {% endif %}
		</td>
        <td>
		{% if lectures_legal_basis|length == 0 %}
            <b><span style="color:Red;">!!!</span></b> Sie haben keine Rechtsgrundlage angegeben (siehe Seite "Lehre") 
			<b><span style="color:Red;">!!!</span></b>
		{% endif %}
		{% if lectures_legal_basis|length > 1 %}
		    <ul>
		    {% for llb in lectures_legal_basis %}
              <li>{{ llb.value }}</li>
		    {% endfor %}
		    </ul>
		  {% else %}
		    {% for llb in lectures_legal_basis %}
              {{ llb.value }}
		    {% endfor %}
		  {% endif %}
        </td>
      </tr>
	  {% endif %}

    </table>
</p>

{% get_value 'project/obligation/contact_data_yes_no' as contact_data_y_n %}
{% get_value 'project/obligation/contact_data_details' as contact_data_details %}

<br>
<b>Datenkategorien</b>
<p>
{% if data_categories|length > 0 or contact_data_y_n.option_uri == "https://fdm.tu-dortmund.de/options/option_consent_gen_yes" %}
  Wir verarbeiten die nachfolgenden Daten der genannten Datenkategorien von Ihnen: 
    <table border="1">
      <tr><th>Datenkategorie </th> <th>Daten </th></tr> 
      {% for data_category in data_categories %}
        <tr>
          <td>
  		    {% get_set_value data_category 'project/obligation/obligation_data_categories/obligation_data_category' as datacat %}
  		    {% if datacat.is_true %}
		      {{ datacat.value }}
		    {% else %}
		      <b><span style="color:Red;">!!!</span></b> Sie haben keine Datenkategorie angeben (siehe Seite "Datenkategorien") <b><span style="color:Red;">!!!</span></b>
		    {% endif %}
		  </td> 
          <td>
		    {% get_set_value data_category 'project/obligation/obligation_data_categories/obligation_data_type' as datatype %}
		    {% if datatype.is_true %}
		      {{ datatype.value }}
		    {% else %}
		      <b><span style="color:Red;">!!!</span></b> Sie haben keine konkreten Daten angeben (siehe Seite "Datenkategorien") <b><span style="color:Red;">!!!</span></b>
		    {% endif %}
		  </td>
        </tr>
      {% endfor %} 
	  {# Kontaktdaten #}
	  {% if contact_data_y_n.option_uri == "https://fdm.tu-dortmund.de/options/option_consent_gen_yes" %}
	    <tr> 
		<td>
		  Kontaktdaten  
	    </td>
	    <td>
		  {% if contact_data_details.is_true %}
		    {{ contact_data_details.value }}
		  {% else %}
		    <b><span style="color:Red;">!!!</span></b> Sie haben keine konkreten Kontaktdaten angeben (siehe Seite "Kontaktdaten der Teilnehmenden") <b><span style="color:Red;">!!!</span></b>
		  {% endif %}
        </td>
	  {% endif %}
    </table>

    <br>
    <p>
	  Informationen zur Datenerhebung:
      <ul>
        {% for data_category in data_categories %}
		  <li> 
		    {% get_set_value data_category 'project/obligation/obligation_data_categories/obligation_data_type_process' as odtp %}
		    {% if odtp.is_true %}
		      {{ odtp.value }}
		    {% else %}
              <b><span style="color:Red;">!!!</span></b> Sie haben keine Informationen zur Datenerhebung eingegeben. Prüfen Sie die Eingabe (siehe Seite "Datenkategorien") oder löschen Sie diesen Hinweis nach dem Export. <b><span style="color:Red;">!!!</span></b>
			{% endif %}
		  </li>
	    {% endfor %} 
      </ul>
    </p>	
{% endif %}
{% if data_categories|length == 0 and data_categories_s|length == 0 %}
    <b><span style="color:Red;">!!!</span></b> Sie haben keine Datenkategorien angeben (siehe Seiten "Datenkategorien" und "Besondere Kategorien") <b><span style="color:Red;">!!!</span></b>
{% endif %}
</p>



{% if data_categories_s|length > 0 %}
<br>
  <b>Daten besonderer Kategorien</b>
<p>
  Wir verarbeiten die nachfolgenden Daten besonderer Kategorien von Ihnen: 
    <table border="1">
      <tr><th>Datenkategorie </th> <th>Daten  </th></tr> 
      {% for data_category_s in data_categories_s %}
        <tr>
          <td>
		    {% get_set_value data_category_s 'project/obligation/obligation_special_category/data_categories_special' as datacat_s %}
  		    {% if datacat_s.is_true %}
		      {{ datacat_s.value }}
		    {% else %}
		      <b><span style="color:Red;">!!!</span></b> Sie haben keine Datenkategorie angeben (siehe Seite "Besondere Kategorien")  <b><span style="color:Red;">!!!</span></b>
		    {% endif %}
		  </td> 
          <td>
            {% get_set_value data_category_s 'project/obligation/obligation_special_category/obligation_data_type_special_category' as datatype_s %}
  		    {% if datatype_s.is_true %}
		      {{ datatype_s.value }}
		    {% else %}
		      <b><span style="color:Red;">!!!</span></b> Sie haben keine konkreten Daten angeben (siehe Seite "Besondere Kategorien") <b><span style="color:Red;">!!!</span></b>
		    {% endif %}
		  </td>
        </tr>
      {% endfor %}
    </table>

    <br>
    <p>
	  Informationen zur Datenerhebung:
      <ul>
        {% for data_category_s in data_categories_s %}
          <li> 
		  {% get_set_value data_category_s 'project/obligation/obligation_special_category/obligation_data_type_special_category_process' as odtps %}
		  {% if odtps.is_true %}
		    {{ odtps.value }}
		  {% else %}
            <b><span style="color:Red;">!!!</span></b> Sie haben keine Informationen zur Datenerhebung eingegeben. Prüfen Sie die Eingabe (siehe Seite "Besondere Kategorien") oder löschen Sie diesen Hinweis nach dem Export <b><span style="color:Red;">!!!</span></b>
		  {% endif %}
		  </li>
	    {% endfor %} 
      </ul>
    </p>

{% else %}
  {# Negativsatz -> wird nicht generiert #}
  {# <p> Wir verarbeiten keine Daten besonderer Kategorien von Ihnen.</p> #}
{% endif %}



{% get_value 'project/obligation/data_categories_criminal_yes_no' as criminal_y_n %}

{% if criminal_y_n.option_uri == "https://fdm.tu-dortmund.de/options/option_consent_gen_yes" %}
<br>
  <b>Strafrechtliche Verurteilungen und Straftaten</b>
<p>
  Wir verarbeiten personenbezogene Daten über strafrechtliche Verurteilungen und Straftaten von Ihnen:  
  <br>
  {% get_values 'project/obligation/data_categories_criminal' set_index=0 as criminal_data %}
  {% if criminal_data|length > 0 %}
    <ul>
      {% for cd in criminal_data %}
        <li>{{cd.value}}</li>
      {% endfor %}
    </ul>  
  {% else %}
    <b><span style="color:Red;">!!!</span></b> Sie haben angegeben, Daten über strafrechtliche Verurteilungen und Straftaten zu verarbeiten, aber keine entsprechenden Daten eingegeben (siehe Seite "Strafrecht") <b><span style="color:Red;">!!!</span></b>
  {% endif %}

  {% get_value 'project/obligation/data_categories_criminal_legal_basis' as data_categories_criminal_legal_basis %}
  <p>
  Rechtsgrundlagen:
  {% if data_categories_criminal_legal_basis.is_true %}
	{{ data_categories_criminal_legal_basis.value }}
  {% else %}
	<b><span style="color:Red;">!!!</span></b> Sie haben keine Rechtsgrundlagen eingegeben (siehe Seite "Strafrecht"). <b><span style="color:Red;">!!!</span></b>
  {% endif %}  
  </p>

  <p>
  {% get_value 'project/obligation/data_categories_criminal_process' as data_categories_criminal_process %}
  {% if data_categories_criminal_process.is_true %}
  Informationen zur Datenerhebung: 
  {{ data_categories_criminal_process.value }}
  {% endif %}
  </p>
</p>
{% endif %}


<br>
<b>Speicherung und Verarbeitung Ihrer Daten</b>
{% get_value 'project/obligation/obligation_storage_description' as storage_description %}
{% if storage_description.is_true %}
  <p>
    {{ storage_description.value }}
  </p>
{% endif %}

{% get_value 'project/obligation/obligation_storage_access' as storage_access %}
{% if storage_access.is_true %}
<p>
  Die folgenden Personen können auf die Daten zugreifen:  
  {{ storage_access.value }}
</p>
{% endif %}

{% get_value 'project/obligation/obligation_storage_duration' as storage_duration %}
{% if storage_duration.is_true %}
<p>
  Wir speichern Ihre personenbezogenen Daten 
    {{ storage_duration.value }}.
  <br>
  Anschließend werden Ihre personenbezogenen Daten gelöscht bzw. es werden nur noch anonymisierte Daten vorgehalten. 
</p>
{% else %}
<p>
  <b><span style="color:Red;">!!!</span></b>
  Sie müssen Angaben zu der Speicherdauer in nicht-anonymisierter Form machen (siehe Seite "Speicherung und Anonymisierung") 
  <b><span style="color:Red;">!!!</span></b>
</p>
{% endif %}



{% get_value 'project/obligation/obligation_publication_y_n' as publication_y_n %}
{% if publication_y_n.option_uri == "https://fdm.tu-dortmund.de/options/option_consent_gen_yes" %}
  {% get_value 'project/obligation/obligation_publication_details' as publication_details %}
    <br>
    <p>
      <b>Wissenschaftliche Veröffentlichung</b>
	  <br>
	  {% if publication_details.is_true %}
  	    {{ publication_details.value }}
	  {% else %}
	    <b><span style="color:Red;">!!!</span></b>
        Sie planen die Nutzung der Daten in wissenschaftlichen Publikationen, stellen aber keine weiteren Details bereit. 
        Bitte überprüfen Sie Ihre Eingabe (siehe Seite "Wissenschaftliche Veröffentlichung") oder löschen Sie diesen Hinweis nach dem Export 
        <b><span style="color:Red;">!!!</span></b>  
      {% endif %}  
    </p>
{% endif %}



{% get_value 'project/obligation/obligation_lectures_y_n' as lectures_y_n %}
{% if lectures_y_n.option_uri == "https://fdm.tu-dortmund.de/options/option_consent_gen_yes" %}
  {% get_value 'project/obligation/obligation_lectures_data' as lectures_data %}
  <br>
  <p>
    <b>Wissenschaftliche Lehre</b>
    <br>
	{% if lectures_data.is_true %}
      {{ lectures_data.value }}
	{% else %}
      <b><span style="color:Red;">!!!</span></b>
      Sie planen die Nutzung der Daten in der Lehre, stellen aber keine weiteren Details bereit. 
      Bitte überprüfen Sie Ihre Eingabe (siehe Seite "Lehre") oder löschen Sie diesen Hinweis nach dem Export 
      <b><span style="color:Red;">!!!</span></b>  
    {% endif %}  
  </p>
{% endif %}



{% get_value 'project/obligation/obligation_profiling_yes_no' as profiling_y_n %}
{% if profiling_y_n.option_uri == "https://fdm.tu-dortmund.de/options/option_consent_gen_yes" %}
<br>
<b>Automatisierte Entscheidungsfindung</b>
<p>
  Es wird eine automatisierte Entscheidungsfindung einschließlich Profiling eingesetzt. 
  <br>
  Diese beruht auf der folgenden Logik: 
  <br>
  {% get_value 'project/obligation/obligation_profiling_details' as profiling_details %}
  {% if profiling_details.is_true %}
    {{ profiling_details.value }}
  {% else %}
    <b><span style="color:Red;">!!!</span></b>
	Sie haben angegeben, automatisierte Entscheidungsfindung/Profiling einzusetzen, aber die Logik nicht angegeben (siehe Seite "Autom. Entscheidung, Profiling")
    <b><span style="color:Red;">!!!</span></b> 
  {% endif %}
</p>
{% endif %}  


{% get_value 'project/obligation/obligation_data_center_repository_y_n' as data_center_repository_y_n %}
{% get_value 'project/obligation/obligation_data_center_repository_category' as data_center_repository_category %}
{% get_value 'project/obligation/obligation_data_center_repository_name' as data_center_repository_name %}
{% get_value 'project/obligation/obligation_data_center_repository_purpose' as data_center_repository_purpose %}
{% get_values 'project/obligation/obligation_data_center_repository_legal_basis' as data_center_repository_legal_basis %}

{% get_value 'project/obligation/obligation_data_center_repository_archiving_y_n' as data_center_repository_archiving_y_n %}
{% get_value 'project/obligation/obligation_data_center_repository_archiving_category' as data_center_repository_archiving_category %}
{% get_value 'project/obligation/obligation_data_center_repository_archiving_name' as data_center_repository_archiving_name %}
{% get_value 'project/obligation/obligation_data_center_repository_archiving_purpose' as data_center_repository_archiving_purpose %}
{% get_values 'project/obligation/obligation_data_center_repository_archiving_legal_basis' as data_center_repository_archiving_legal_basis %}

{% if receivers|length > 0 or data_center_repository_y_n.option_uri == "https://fdm.tu-dortmund.de/options/option_consent_gen_yes" or data_center_repository_archiving_y_n.option_uri == "https://fdm.tu-dortmund.de/options/option_consent_gen_yes" %}
<br>
<b>Empfänger oder Empfängerkategorien personenbezogener Daten</b>
<p>
  Ihre personenbezogenen Daten werden an folgende Empfänger
  bzw. Kategorien von Empfängern weitergegeben:
  <table border="1">
  <tr><th>Empfängerkategorie</th> <th>Konkrete Empfänger</th> <th>Zweck</th> <th>Rechtsgrundlage/Übermittlungsbasis</th></tr> 
  {% for receiver in receivers %}  
    <tr>
	  <td> {% get_set_value receiver 'project/obligation/receiver/receiver_category' as receiver_category %}
        {% if receiver_category.is_true %}
          {{ receiver_category.value }}
        {% else %}
          <b><span style="color:Red;">!!!</span></b>Empfängerkategorie fehlt (siehe Seite "Weitere Empfänger") <b><span style="color:Red;">!!!</span></b>
        {% endif %}
	  </td>
      <td>{% get_set_value receiver 'project/obligation/receiver/receiver_name' as receiver_name %} 
        {% if receiver_name.is_true %}
          {{ receiver_name.value }}
        {% else %}
          <b><span style="color:Red;">!!!</span></b>Empfängername fehlt (siehe Seite "Weitere Empfänger") <b><span style="color:Red;">!!!</span></b>
        {% endif %}
      </td> 
      <td>{% get_set_value receiver 'project/obligation/receiver/receiver_purpose' as receiver_purpose %} 
        {% if receiver_purpose.is_true %}
          {{ receiver_purpose.value }}
        {% else %}
          <b><span style="color:Red;">!!!</span></b>Zweck fehlt (siehe Seite "Weitere Empfänger") <b><span style="color:Red;">!!!</span></b>
        {% endif %}
      </td>
      <td>
        {% get_set_values receiver 'project/obligation/receiver/receiver_legal_basis' as receiver_lbs %}
        {% if receiver_lbs|length == 0 %}
          <b><span style="color:Red;">!!!</span></b>Rechtsgrundlage fehlt (siehe Seite "Weitere Empfänger") <b><span style="color:Red;">!!!</span></b>
        {% endif %}
        {% if receiver_lbs|length > 1 %}
          <ul>
          {% for rlb in receiver_lbs %}
            <li>{{ rlb.value }}</li>
          {% endfor %}
          </ul>
        {% else %}
          {% for rlb in receiver_lbs %}
            {{ rlb.value }}
          {% endfor %}
        {% endif %}
      </td>
	</tr> 
  {% endfor %}

	{% if data_center_repository_y_n.option_uri == "https://fdm.tu-dortmund.de/options/option_consent_gen_yes" %}
      <tr>
        <td> 
        {% if data_center_repository_category.is_true %}
          {{ data_center_repository_category.value }}
        {% else %}
          <b><span style="color:Red;">!!!</span></b>Kategorie der Daten-Empfänger fehlt (siehe Seite "Datenpublikation") <b><span style="color:Red;">!!!</span></b>
        {% endif %}
		</td>
		<td> {{ data_center_repository_name.value }} </td>
		<td>  
		  {% if data_center_repository_purpose.is_true %}
            {{ data_center_repository_purpose.value }}
		  {% else %}
		    <b><span style="color:Red;">!!!</span></b> Sie haben keinen Zweck angegeben (siehe Seite "Datenpublikation") 
		    <b><span style="color:Red;">!!!</span></b>
		  {% endif %}
		</td>
		<td>
		{% if data_center_repository_legal_basis|length == 0 %}
            <b><span style="color:Red;">!!!</span></b> Sie haben keine Rechtsgrundlage angegeben (siehe Seite "Datenpublikation") 
			<b><span style="color:Red;">!!!</span></b>
		{% endif %}
		{% if data_center_repository_legal_basis|length > 1 %}
		    <ul>
		    {% for dclb in data_center_repository_legal_basis %}
              <li>{{ dclb.value }}</li>
		    {% endfor %}
		    </ul>
		  {% else %}
		    {% for dclb in data_center_repository_legal_basis %}
              {{ dclb.value }}
		    {% endfor %}
		  {% endif %}
        </td>
      </tr>
	  {% endif %}	  

      {% if data_center_repository_archiving_y_n.option_uri == "https://fdm.tu-dortmund.de/options/option_consent_gen_yes" %}
	  <tr>
	    <td> 
	    {% if data_center_repository_archiving_category.is_true %}
          {{ data_center_repository_archiving_category.value }}
        {% else %}
          <b><span style="color:Red;">!!!</span></b>Kategorie der Daten-Empfänger fehlt (siehe Seite "Archivierung") <b><span style="color:Red;">!!!</span></b>
        {% endif %}
		</td>
		<td> {{ data_center_repository_archiving_name.value }} </td>
        <td> 
		  {% if data_center_repository_archiving_purpose.is_true %}
            {{ data_center_repository_archiving_purpose.value }}
		  {% else %}
		    <b><span style="color:Red;">!!!</span></b> Sie haben keinen Zweck angegeben (siehe Seite "Archivierung") 
		    <b><span style="color:Red;">!!!</span></b>
		  {% endif %}
		</td>
        <td>
		{% if data_center_repository_archiving_legal_basis|length == 0 %}
            <b><span style="color:Red;">!!!</span></b> Sie haben keine Rechtsgrundlage angegeben (siehe Seite "Archivierung") 
			<b><span style="color:Red;">!!!</span></b>
		{% endif %}
		{% if data_center_repository_archiving_legal_basis|length > 1 %}
		    <ul>
		    {% for dcalb in data_center_repository_archiving_legal_basis %}
              <li>{{ dcalb.value }}</li>
		    {% endfor %}
		    </ul>
		  {% else %}
		    {% for dcalb in data_center_repository_archiving_legal_basis %}
              {{ dcalb.value }}
		    {% endfor %}
		  {% endif %}
        </td>
      </tr>
	  {% endif %}

  </table>  
</p>
{% else %}
  {# Negativsatz #}
  {#<p> Eine Weitergabe Ihrer personenbezogenen Daten erfolgt nicht. </p> #}
{% endif %}




