{% comment %}
{# In die Drittland-Übertragung muss nicht eingewilligt werden, daher hier auskommentiert #}
{% if third_countries|length > 0 %}
<br>
<p>
  {% for third in third_countries %}

    {% get_set_value third 'project/obligation/obligation_third_country/third_country_name' as third_country_name %}
    {% get_set_value third 'project/obligation/obligation_third_country/third_country_adequacy_yes_no' as third_adequacy %}
    {% get_set_value third 'project/obligation/obligation_third_country/third_country_guarantees' as third_guarantee %}
	{% get_set_value third 'project/obligation/obligation_third_country/third_country_purpose' as third_guarantee_purpose %}


    {% if third_adequacy.option_uri == "https://fdm.tu-dortmund.de/options/option_consent_gen_yes"%}
	  {# Angemessenheitsbeschluss vorhanden #}
	    <p>
        Ich willige ein, dass meine personenbezogenen Daten zu dem Zweck           
	    {{ third_guarantee_purpose.value }}
		an 
		{{ third_country_name.value }}
		außerhalb der EU/des europäischen Wirtschaftsraums übermittelt werden. 
		Für das Land besteht ein Angemessenheitsbeschluss der Europäischen Kommission gemäß Art. 45 DSGVO, 
		sodass ein der EU gleichwertiges Datenschutzniveau gewährleistet ist.
		</p>
        <br>

        <p>
        &#x2610; Ja &#x2610; Nein
        </p> 
    {% else %}

      {% if third_guarantee.option_uri == "https://fdm.tu-dortmund.de/options/option_third_country_guarantee_no_guarantees" %}
	    {# kein Angemessenheitsbeschluss, keine Garantien #}
        {# dieser Fall wird nicht abgedeckt! #}
		{# hier müssen die Forschenden zu Datenschutzbeauftragten! #}
      {% else %}
	  	<p>
        {# kein Angemessenheitsbeschluss, aber Garantien vorhanden #}

		Ich willige ein, dass meine personenbezogenen Daten zum Zweck 
	    {{ third_guarantee_purpose.value }}
		an 
		{{ third_country_name.value }}		
		außerhalb der EU/des europäischen Wirtschaftsraums übermittelt werden.
		Für dieses Land besteht kein Angemessenheitsbeschluss der Europäischen Kommission. 
		Die Übermittlung erfolgt auf Grundlage geeigneter Garantien gemäß Art. 46 DSGVO: 
		<br>
        {% if third_guarantee.is_true %}
          {{ third_guarantee.text }}
        {% else %}
        <br>
          <b><span style="color:Red;">!!!</span></b>Die Garantien wurden nicht beschrieben (siehe Seite "Drittland") <b><span style="color:Red;">!!!</span></b>
        <br>
        {% endif %} 
		<br> 

		Mir ist bekannt, dass trotz dieser Garantien kein mit der EU vergleichbares Datenschutzniveau 
		vollständig gewährleistet werden kann und staatliche Zugriffe auf meine Daten nicht ausgeschlossen sind. 
		</p>
        <br>

        <p>
        &#x2610; Ja &#x2610; Nein
        </p> 
      {% endif %}
    {% endif %}
  {% endfor %}
{% endif %}
{% endcomment %}


